import numpy as np

def rolling_window_2d(a, size, center=True):
    if not isinstance(a, np.ndarray):
        raise TypeError("Input must be a numpy array")
    if size is None:
        raise ValueError("Size must be provided")
    if isinstance(a, np.ndarray):
        if a.ndim != 2:
            raise ValueError("Array must be 2D")

    size = int(size)
    if size < 1:
        raise ValueError("Window size must be at least 1")

    h, w = a.shape
    if size > max(h, w):
        raise ValueError(f"Window size {size} must be less than or equal to array dimensions")

    result = []

    for i in range(h):
        for j in range(w):
            x = np.lib.stride_tricks.sliding_window_view(a, (size, size))
            # Extract window centered at (i, j) starting at (i-size+1, j-size+1)
            if center:
                if i > h - size:
                    x = x[i - size + 1:, :]
                if j > w - size:
                    x = x[:, j - size + 1:]
            else:
                if i < 0:
                    x = x[:0, :]
                if j < 0:
                    x = x[:, :0]
            result.append(x)

    return np.array(result)
